@Injectable()
export class ResponseEnvelopeInterceptor<T>
  implements NestInterceptor<T, ResponseEnvelope<T>>
{
  intercept(
    _context: ExecutionContext,
    next: CallHandler<T>,
  ): Observable<ResponseEnvelope<T>> {
    return next.handle().pipe(
      map((value) => {
        if (isResponseEnvelope(value)) {
          return value;
        }

        return {
          data: value,
        };
      }),
    );
  }
}

function isResponseEnvelope<T>(value: T): value is ResponseEnvelope<unknown> {
  return (
    typeof value === 'object' &&
    value !== null &&
    'data' in value &&
    !Array.isArray(value)
  );
}

